(function () {
  "use strict";

  var MONTHS = [
    "JAN", "FEB", "MAR", "APR", "MAY", "JUN",
    "JUL", "AUG", "SEP", "OCT", "NOV", "DEC"
  ];
  var MONTH_NAMES = [
    "January", "February", "March", "April", "May", "June",
    "July", "August", "September", "October", "November", "December"
  ];
  var WEEKDAYS = ["Mon", "Tue", "Wed", "Thu", "Fri", "Sat", "Sun"];
  var DEFAULT_WEEK_START = "2026-06-01";
  var DEFAULT_SELECTED_DATE = "2026-06-03";
  var SEASONS = ["All", "SP27", "SU27", "FA27", "HO27", "SP28"];
  var CALENDAR_VIEWS = [
    { id: "timeline", label: "Timeline View" },
    { id: "gantt", label: "Gantt" },
    { id: "list", label: "List" },
    { id: "season-grid", label: "Season Grid" }
  ];
  var PERIODS = [
    { id: "week", label: "1 week" },
    { id: "multi-week", label: "Multi-week" },
    { id: "month", label: "Month" },
    { id: "multi-month", label: "Multi-month" },
    { id: "quarter", label: "Quarter" },
    { id: "season", label: "Season" }
  ];

  var EMBEDDED = window.WT_SYSTEM_EMBEDDED || { milestones: [], holidays: [] };

  var state = {
    section: "calendar",
    view: "display",
    calendarView: "timeline",
    period: "week",
    weekStart: DEFAULT_WEEK_START,
    selectedDate: DEFAULT_SELECTED_DATE,
    search: "",
    deadlineOnly: false,
    actionMessage: "",
    season: "All"
  };

  function boot() {
    var roots = document.querySelectorAll("[data-wt-system]");
    for (var i = 0; i < roots.length; i += 1) {
      roots[i].classList.add("wt-root");
      applyViewportFit(roots[i]);
      roots[i].innerHTML = renderApp(roots[i]);
      bind(roots[i]);
      updateClock(roots[i]);
    }
  }

  function bind(root) {
    root.addEventListener("click", function (event) {
      var sectionButton = event.target.closest("[data-section]");
      var viewButton = event.target.closest("[data-view]");
      var dateButton = event.target.closest("[data-date]");
      var weekButton = event.target.closest("[data-week-shift]");
      var todayButton = event.target.closest("[data-today]");
      var seasonButton = event.target.closest("[data-season]");
      var calendarViewButton = event.target.closest("[data-calendar-view]");
      var periodButton = event.target.closest("[data-period]");
      var deadlineButton = event.target.closest("[data-deadline-toggle]");
      var exportButton = event.target.closest("[data-export]");
      var clearSearchButton = event.target.closest("[data-clear-search]");

      if (sectionButton && root.contains(sectionButton)) {
        state.section = sectionButton.getAttribute("data-section");
        state.view = "display";
        render(root);
      }

      if (viewButton && root.contains(viewButton)) {
        state.view = viewButton.getAttribute("data-view");
        if (state.view === "edit") state.section = "calendar";
        render(root);
      }

      if (dateButton && root.contains(dateButton)) {
        state.selectedDate = dateButton.getAttribute("data-date");
        render(root);
      }

      if (weekButton && root.contains(weekButton)) {
        moveRange(Number(weekButton.getAttribute("data-week-shift")));
        state.selectedDate = currentRange().start;
        render(root);
      }

      if (todayButton && root.contains(todayButton)) {
        var todayIso = toIso(new Date());
        state.weekStart = periodAnchor(todayIso, state.period);
        state.selectedDate = todayIso;
        render(root);
      }

      if (calendarViewButton && root.contains(calendarViewButton)) {
        state.calendarView = calendarViewButton.getAttribute("data-calendar-view");
        state.actionMessage = "";
        render(root);
      }

      if (periodButton && root.contains(periodButton)) {
        state.period = periodButton.getAttribute("data-period");
        state.weekStart = periodAnchor(state.selectedDate, state.period);
        state.actionMessage = "";
        render(root);
      }

      if (deadlineButton && root.contains(deadlineButton)) {
        state.deadlineOnly = !state.deadlineOnly;
        state.actionMessage = state.deadlineOnly ? "Deadline filter is on." : "";
        render(root);
      }

      if (exportButton && root.contains(exportButton)) {
        exportCurrentRange(root);
      }

      if (clearSearchButton && root.contains(clearSearchButton)) {
        state.search = "";
        render(root);
      }

      if (seasonButton && root.contains(seasonButton)) {
        state.season = seasonButton.getAttribute("data-season");
        render(root);
      }

    });

    root.addEventListener("input", function (event) {
      var searchInput = event.target.closest("[data-calendar-search]");
      if (!searchInput || !root.contains(searchInput)) return;
      state.search = searchInput.value;
      render(root);
      var nextInput = root.querySelector("[data-calendar-search]");
      if (nextInput) {
        nextInput.focus();
        nextInput.setSelectionRange(state.search.length, state.search.length);
      }
    });

    root.addEventListener("submit", function (event) {
      var form = event.target.closest(".wt-edit-form");
      if (!form) return;
      event.preventDefault();
      submitSchedule(root, form);
    });

    window.setInterval(function () {
      updateClock(root);
    }, 60000);

    window.addEventListener("resize", function () {
      applyViewportFit(root);
    });
  }

  function render(root) {
    applyViewportFit(root);
    root.innerHTML = renderApp(root);
    updateClock(root);
  }

  function applyViewportFit(root) {
    if (root.getAttribute("data-wt-standalone") !== "true") return;
    var designWidth = 1920;
    var designHeight = 1080;
    var scale = window.innerWidth / designWidth;
    root.setAttribute("data-wt-fit", "viewport");
    root.style.setProperty("--wt-fit-scale", String(scale));
    root.style.setProperty("--wt-fit-width", designWidth + "px");
    root.style.setProperty("--wt-fit-height", designHeight + "px");
  }

  function renderApp(root) {
    return [
      '<div class="wt-app is-' + text(state.section) + ' is-' + text(state.view) + '">',
      renderSidebar(),
      state.view === "edit" ? renderEditor(root) : renderShell(root),
      '</div>'
    ].join("");
  }

  function renderSidebar() {
    return [
      '<aside class="wt-sidebar" aria-label="WT System navigation">',
      '<div class="wt-brand">',
      '<span class="wt-brand-mark">WT</span>',
      '<div><b>WT_Flow</b></div>',
      '</div>',
      '<nav class="wt-primary-nav" aria-label="Primary">',
      navItem("dashboard", "Dashboard"),
      navItem("creation", "Creation Plan"),
      navItem("calendar", "Calendar"),
      navItem("projector", "Projector View"),
      navItem("libraries", "Libraries"),
      '</nav>',
      '</aside>'
    ].join("");
  }

  function navItem(section, label) {
    return [
      '<button type="button" class="' + (state.section === section ? "active" : "") + '" data-section="' + text(section) + '">',
      icon(section),
      '<span>' + text(label) + '</span>',
      '</button>'
    ].join("");
  }

  function renderShell(root) {
    return [
      '<main class="wt-main" aria-label="WT System workspace">',
      renderToolbar(),
      '<div class="wt-workspace">',
      renderSection(root),
      '</div>',
      '</main>'
    ].join("");
  }

  function renderToolbar() {
    return [
      '<header class="wt-toolbar wt-flow-topbar">',
      '<div></div>',
      '<div class="wt-flow-breadcrumb">' + text(sectionTitle()) + '</div>',
      '<div></div>',
      '</header>'
    ].join("");
  }

  function sectionTitle() {
    if (state.section === "dashboard") return "Dashboard";
    if (state.section === "creation") return "Creation Plan";
    if (state.section === "projector") return "Projector View";
    if (state.section === "libraries") return "Libraries";
    return "Calendar";
  }

  function renderSection(root) {
    if (state.section === "dashboard") return renderDashboard();
    if (state.section === "creation") return renderCreationPlan();
    if (state.section === "projector") return renderDashboard();
    if (state.section === "libraries") return renderLibraries();
    return renderCalendarWorkspace(root);
  }

  function renderCalendarWorkspace() {
    return [
      '<section class="wt-calendar-page wt-flow-calendar-page wt-period-' + text(state.period) + ' wt-view-' + text(state.calendarView) + '">',
      '<header class="wt-flow-page-head">',
      '<div class="wt-flow-heading"><h1>Calendar</h1></div>',
      '</header>',
      renderCalendarControls(),
      '<div class="wt-calendar-layout wt-flow-calendar-layout">',
      renderCalendarBoard(false),
      '</div>',
      '</section>'
    ].join("");
  }

  function renderCalendarControls() {
    var range = currentRange();
    var rangeEvents = eventsForCurrentRange();
    return [
      '<section class="wt-control-strip wt-flow-control-strip" aria-label="Calendar filters">',
      '<div class="wt-filter-row wt-flow-filter-row">',
      '<span class="wt-event-count">' + text(rangeEvents.length) + ' Events</span>',
      '<span class="wt-flow-divider"></span>',
      '<label class="wt-search wt-flow-search"><span class="wt-search-icon">' + icon("search") + '</span><input data-calendar-search type="search" value="' + text(state.search) + '" placeholder="Search"></label>',
      renderFlowFilter("Season", SEASONS, "season", state.season),
      '<button class="wt-deadline-toggle wt-flow-pill ' + (state.deadlineOnly ? "active" : "") + '" type="button" data-deadline-toggle>' + icon("flag") + '<span>Deadline</span></button>',
      '</div>',
      '<div class="wt-action-buttons wt-flow-actions">',
      '<button type="button" data-export title="Export current range" aria-label="Export">' + icon("download") + '</button>',
      '<button type="button" data-view="edit">' + icon("plus") + '<span>Create</span></button>',
      '</div>',
      '<div class="wt-range-row wt-flow-range-row">',
      '<div class="wt-range-title"><strong>' + text(formatRange(range)) + '</strong></div>',
      '<div class="wt-flow-view-controls">',
      renderPicker("View", calendarViewLabel(state.calendarView), CALENDAR_VIEWS, "calendar-view", state.calendarView),
      renderPicker("Range", periodLabel(state.period), PERIODS, "period", state.period),
      '<div class="wt-week-controls">',
      '<button type="button" data-week-shift="-1" aria-label="Previous">' + icon("chevron-left") + '</button>',
      '<button type="button" data-today>Today</button>',
      '<button type="button" data-week-shift="1" aria-label="Next">' + icon("chevron-right") + '</button>',
      '</div>',
      '</div>',
      '</div>',
      state.search ? '<div class="wt-filter-note">Search: <b>' + text(state.search) + '</b><button type="button" data-clear-search>Clear</button></div>' : "",
      state.actionMessage ? '<div class="wt-action-message">' + text(state.actionMessage) + '</div>' : "",
      '</section>'
    ].join("");
  }

  function renderFlowFilter(label, options, dataName, activeValue) {
    return [
      '<details class="wt-flow-filter">',
      '<summary class="wt-flow-pill">' + text(label) + '</summary>',
      '<div class="wt-picker-menu">',
      options.map(function (option) {
        return '<button class="' + (option === activeValue ? "active" : "") + '" type="button" data-' + text(dataName) + '="' + text(option) + '">' + text(option) + '</button>';
      }).join(""),
      '</div>',
      '</details>'
    ].join("");
  }

  function renderPicker(label, value, options, dataName, activeValue) {
    return [
      '<details class="wt-picker">',
      '<summary><small>' + text(label) + '</small><b>' + text(value) + '</b></summary>',
      '<div class="wt-picker-menu">',
      options.map(function (option) {
        return '<button class="' + (option.id === activeValue ? "active" : "") + '" type="button" data-' + text(dataName) + '="' + text(option.id) + '">' + text(option.label) + '</button>';
      }).join(""),
      '</div>',
      '</details>'
    ].join("");
  }

  function filterButton(type, value, active) {
    return '<button class="' + (active ? "active" : "") + '" type="button" data-' + text(type) + '="' + text(value) + '">' + text(value) + '</button>';
  }

  function icon(name) {
    var paths = {
      dashboard: '<rect x="3" y="3" width="7" height="7" rx="1.5"></rect><rect x="14" y="3" width="7" height="7" rx="1.5"></rect><rect x="14" y="14" width="7" height="7" rx="1.5"></rect><rect x="3" y="14" width="7" height="7" rx="1.5"></rect>',
      creation: '<path d="M15 5l4 4"></path><path d="M13.5 6.5l4 4L7 21H3v-4L13.5 6.5z"></path><path d="M16 3l5 5"></path>',
      calendar: '<rect x="3" y="4" width="18" height="17" rx="2"></rect><path d="M8 2v4"></path><path d="M16 2v4"></path><path d="M3 10h18"></path><path d="M8 14h.01"></path><path d="M12 14h.01"></path><path d="M16 14h.01"></path>',
      projector: '<rect x="3" y="4" width="18" height="12" rx="2"></rect><path d="M8 20h8"></path><path d="M12 16v4"></path>',
      libraries: '<path d="M4 19.5V5.75A2.75 2.75 0 0 1 6.75 3H20v16H6.75A2.75 2.75 0 0 0 4 21.75"></path><path d="M8 7h8"></path><path d="M8 11h6"></path>',
      search: '<circle cx="11" cy="11" r="7"></circle><path d="M20 20l-3.5-3.5"></path>',
      flag: '<path d="M5 21V4"></path><path d="M5 4h12l-1.5 4L17 12H5"></path>',
      download: '<path d="M12 3v12"></path><path d="M7 10l5 5 5-5"></path><path d="M4 21h16"></path>',
      plus: '<path d="M12 5v14"></path><path d="M5 12h14"></path>',
      "chevron-left": '<path d="M15 18l-6-6 6-6"></path>',
      "chevron-right": '<path d="M9 18l6-6-6-6"></path>'
    };
    var body = paths[name] || paths.dashboard;
    return '<svg class="wt-icon wt-icon-' + text(name) + '" aria-hidden="true" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="1.8" stroke-linecap="round" stroke-linejoin="round">' + body + '</svg>';
  }

  function renderCalendarBoard(compact) {
    if (state.calendarView === "gantt") return renderGanttBoard(compact);
    if (state.calendarView === "list") return renderListBoard(compact);
    if (state.calendarView === "season-grid") return renderSeasonGridBoard(compact);
    return renderTimelineBoard(compact);
  }

  function renderTimelineBoard(compact) {
    var range = currentRange();
    var units = timelineUnits(range);
    var events = eventsForCurrentRange();
    var lanes = timelineLanes(events);
    return [
      '<section class="wt-timeline-board wt-flow-timeline-board ' + (compact ? "compact" : "") + '" aria-label="Timeline calendar">',
      '<div class="wt-timeline-head" style="--wt-cols:' + text(units.length) + '">',
      '<span class="wt-timeline-corner"></span>',
      units.map(function (unit) {
        return '<span class="' + (unitHasToday(unit) ? "today" : "") + '"><b>' + text(unit.label) + '</b><small>' + text(unit.caption) + '</small></span>';
      }).join(""),
      '</div>',
      '<div class="wt-timeline-body">',
      lanes.length ? lanes.map(function (lane) {
        return renderTimelineLane(lane, units, compact);
      }).join("") : renderEmptyBoard("No events in this range."),
      '</div>',
      '</section>'
    ].join("");
  }

  function renderTimelineLane(lane, units, compact) {
    var rows = assignLaneRows(lane.events, units);
    var rowCount = Math.max(1, rows.length);
    return [
      '<article class="wt-timeline-lane" style="--wt-lane-rows:' + text(rowCount) + '">',
      '<div class="wt-timeline-meta"><b>' + text(lane.label) + '</b></div>',
      '<div class="wt-timeline-track" style="--wt-cols:' + text(units.length) + '; --wt-lane-rows:' + text(rowCount) + '">',
      lane.events.map(function (event) {
        var position = eventUnitPosition(event, units);
        var row = event.__laneRow || 1;
        return renderTimelineEvent(event, position, row, compact);
      }).join(""),
      '</div>',
      '</article>'
    ].join("");
  }

  function renderTimelineEvent(event, position, row, compact) {
    var selected = event.date === state.selectedDate ? " is-selected" : "";
    return [
      '<button type="button" class="wt-timeline-bar ' + text(eventAccentClass(event)) + ' wt-kind-' + text(event.kind) + selected + '" data-date="' + text(event.date) + '" title="' + text(eventTooltip(event)) + '" aria-label="' + text(eventTooltip(event)) + '" style="grid-column:' + text(position.start) + ' / span ' + text(position.span) + '; --wt-event-row:' + text(row) + '">',
      '<b>' + text(shortTitle(event.title, compact ? 34 : 54)) + '</b>',
      '<span>' + text(event.gate || event.owner || "WT") + '</span>',
      '</button>'
    ].join("");
  }

  function timelineLanes(events) {
    var grouped = {};
    events.forEach(function (event) {
      var label = event.season || "All";
      if (!grouped[label]) grouped[label] = [];
      grouped[label].push(event);
    });
    return Object.keys(grouped).sort(compareSeasonLabels).map(function (label) {
      return {
        label: label,
        events: grouped[label].sort(function (a, b) {
          return (a.date + (a.endDate || a.date) + a.title).localeCompare(b.date + (b.endDate || b.date) + b.title);
        })
      };
    });
  }

  function assignLaneRows(events, units) {
    var rowEnds = [];
    events.forEach(function (event) {
      var position = eventUnitPosition(event, units);
      var placed = false;
      for (var i = 0; i < rowEnds.length; i += 1) {
        if (position.start > rowEnds[i]) {
          event.__laneRow = i + 1;
          rowEnds[i] = position.start + position.span - 1;
          placed = true;
          break;
        }
      }
      if (!placed) {
        rowEnds.push(position.start + position.span - 1);
        event.__laneRow = rowEnds.length;
      }
    });
    return rowEnds;
  }

  function compareSeasonLabels(a, b) {
    var order = ["FA26", "SP27", "SU27", "FA27", "HO27", "SP28", "All"];
    var ai = order.indexOf(a);
    var bi = order.indexOf(b);
    if (ai >= 0 || bi >= 0) return (ai < 0 ? 999 : ai) - (bi < 0 ? 999 : bi);
    return a.localeCompare(b);
  }

  function eventAccentClass(event) {
    return "wt-accent-default";
  }

  function shortTitle(value, maxLength) {
    var stringValue = String(value || "");
    if (stringValue.length <= maxLength) return stringValue;
    return stringValue.slice(0, maxLength - 3).replace(/\s+\S*$/, "") + "...";
  }

  function renderGanttBoard(compact) {
    var range = currentRange();
    var units = timelineUnits(range);
    var events = eventsForCurrentRange();
    var groups = unique(events.map(function (event) { return event.season || "All"; })).slice(0, compact ? 5 : 8);
    return [
      '<section class="wt-gantt-board ' + (compact ? "compact" : "") + '" aria-label="Gantt calendar">',
      '<div class="wt-timeline-head" style="--wt-cols:' + text(units.length) + '">',
      '<span class="wt-timeline-corner"></span>',
      units.map(function (unit) {
        return '<span><b>' + text(unit.label) + '</b><small>' + text(unit.caption) + '</small></span>';
      }).join(""),
      '</div>',
      '<div class="wt-gantt-body">',
      groups.length ? groups.map(function (season) {
        var seasonEvents = events.filter(function (event) { return (event.season || "All") === season; });
        if (compact) seasonEvents = seasonEvents.slice(0, 8);
        return renderGanttLane(season, seasonEvents, units);
      }).join("") : renderEmptyBoard("No events in this range."),
      '</div>',
      '</section>'
    ].join("");
  }

  function renderGanttLane(label, events, units) {
    var rows = assignLaneRows(events, units);
    var rowCount = Math.max(1, rows.length);
    return [
      '<article class="wt-gantt-lane" style="--wt-gantt-rows:' + text(rowCount) + '">',
      '<div class="wt-gantt-label"><b>' + text(label) + '</b><small>' + text(events.length) + ' events</small></div>',
      '<div class="wt-gantt-track" style="--wt-cols:' + text(units.length) + '; --wt-gantt-rows:' + text(rowCount) + '">',
      events.map(function (event) {
        var position = eventUnitPosition(event, units);
        var row = event.__laneRow || 1;
        var selected = event.date === state.selectedDate ? " is-selected" : "";
        return '<button type="button" class="wt-gantt-chip wt-kind-' + text(event.kind) + selected + '" data-date="' + text(event.date) + '" title="' + text(eventTooltip(event)) + '" aria-label="' + text(eventTooltip(event)) + '" style="grid-column:' + text(position.start) + ' / span ' + text(position.span) + '; --wt-row:' + text(row) + '"><span>' + text(formatDateShort(event.date) + " · " + (event.gate || event.kind)) + '</span><b>' + text(event.title) + '</b></button>';
      }).join(""),
      '</div>',
      '</article>'
    ].join("");
  }

  function renderListBoard(compact) {
    var events = eventsForCurrentRange();
    var maxRows = compact ? 10 : events.length;
    return [
      '<section class="wt-list-board ' + (compact ? "compact" : "") + '" aria-label="List calendar">',
      '<header><span>Date</span><span>Event</span><span>Season</span><span>Owner</span></header>',
      '<div>',
      events.length ? events.slice(0, maxRows).map(renderListRow).join("") : renderEmptyBoard("No events in this range."),
      compact && events.length > maxRows ? '<div class="wt-board-more">+' + text(events.length - maxRows) + ' more events in filters</div>' : "",
      '</div>',
      '</section>'
    ].join("");
  }

  function renderListRow(event) {
    var selected = event.date === state.selectedDate ? " is-selected" : "";
    return [
      '<button type="button" class="wt-list-row wt-kind-' + text(event.kind) + selected + '" data-date="' + text(event.date) + '" title="' + text(eventTooltip(event)) + '" aria-label="' + text(eventTooltip(event)) + '">',
      '<time>' + text(formatDateShort(event.date)) + '</time>',
      '<b>' + text(event.title) + '</b>',
      '<span>' + text(event.season || "All") + '</span>',
      '<small>' + text(event.gate || event.owner || "WT") + '</small>',
      '</button>'
    ].join("");
  }

  function renderSeasonGridBoard(compact) {
    var range = currentRange();
    var events = eventsForCurrentRange();
    var seasons = unique(events.map(function (event) { return event.season || "All"; })).slice(0, compact ? 5 : 10);
    var months = monthUnits(range);
    return [
      '<section class="wt-season-grid-board ' + (compact ? "compact" : "") + '" aria-label="Season grid calendar">',
      '<div class="wt-season-grid-head" style="--wt-cols:' + text(months.length) + '">',
      '<span>Season</span>',
      months.map(function (month) { return '<b>' + text(month.label) + '</b>'; }).join(""),
      '</div>',
      '<div class="wt-season-grid-body">',
      seasons.length ? seasons.map(function (season) {
        return renderSeasonGridRow(season, months, events.filter(function (event) { return (event.season || "All") === season; }), compact);
      }).join("") : renderEmptyBoard("No season data in this range."),
      '</div>',
      '</section>'
    ].join("");
  }

  function renderSeasonGridRow(season, months, events, compact) {
    return [
      '<article class="wt-season-grid-row" style="--wt-cols:' + text(months.length) + '">',
      '<div class="wt-season-grid-label"><b>' + text(season) + '</b><small>' + text(events.length) + ' milestones</small></div>',
      months.map(function (month) {
        var monthEvents = events.filter(function (event) {
          return event.date >= month.start && event.date <= month.end;
        }).slice(0, compact ? 2 : 5);
        return '<div class="wt-season-cell">' + (monthEvents.length ? monthEvents.map(function (event) {
          var selected = event.date === state.selectedDate ? " is-selected" : "";
          return '<button type="button" class="wt-season-dot wt-kind-' + text(event.kind) + selected + '" data-date="' + text(event.date) + '" title="' + text(eventTooltip(event)) + '" aria-label="' + text(eventTooltip(event)) + '"><span>' + text(dayOfMonth(event.date)) + '</span><b>' + text(event.gate || event.kind) + '</b></button>';
        }).join("") : '<span class="wt-season-empty"></span>') + '</div>';
      }).join(""),
      '</article>'
    ].join("");
  }

  function renderEmptyBoard(message) {
    return '<div class="wt-empty-board">' + text(message) + '</div>';
  }

  function renderWeekBoard(compact) {
    var days = weekDays(state.weekStart);
    return [
      '<section class="wt-week-board ' + (compact ? "compact" : "") + '" aria-label="Weekly calendar">',
      '<div class="wt-week-head">',
      days.map(function (date) {
        return '<button type="button" class="' + (date === state.selectedDate ? "active" : "") + '" data-date="' + text(date) + '"><span>' + text(dayNameShort(date)) + '</span><b>' + text(dayOfMonth(date)) + '</b></button>';
      }).join(""),
      '</div>',
      '<div class="wt-week-grid">',
      days.map(function (date) {
        return renderDayColumn(date, compact);
      }).join(""),
      '</div>',
      '</section>'
    ].join("");
  }

  function renderDayColumn(date, compact) {
    var events = filteredEventsForDate(date);
    var cls = date === state.selectedDate ? " active" : "";
    return [
      '<article class="wt-day-column' + cls + '" data-day="' + text(date) + '">',
      events.length ? events.slice(0, compact ? 4 : 8).map(function (event) {
        return renderEventCard(event, compact);
      }).join("") : '<div class="wt-empty-slot"></div>',
      events.length > (compact ? 4 : 8) ? '<small class="wt-more">+' + text(events.length - (compact ? 4 : 8)) + ' more</small>' : "",
      '</article>'
    ].join("");
  }

  function renderEventCard(event, compact) {
    var selected = event.date === state.selectedDate ? " is-selected" : "";
    return [
      '<button type="button" class="wt-event wt-kind-' + text(event.kind) + selected + '" data-date="' + text(event.date) + '" title="' + text(eventTooltip(event)) + '" aria-label="' + text(eventTooltip(event)) + '">',
      '<span>' + text(event.season || "WT") + '</span>',
      '<b>' + text(event.title) + '</b>',
      compact ? "" : '<small>' + text(event.time || event.gate || "All day") + ' · ' + text(event.owner || "WT") + '</small>',
      '</button>'
    ].join("");
  }

  function renderInspector() {
    var selectedEvents = filteredEventsForDate(state.selectedDate);
    var nextDeadlines = normalizedEvents().filter(matchesFilters).filter(function (event) {
      return event.date >= state.selectedDate && (event.kind === "deadline" || event.kind === "handoff");
    }).slice(0, 5);
    return [
      '<aside class="wt-inspector" aria-label="Selected day details">',
      '<div class="wt-inspector-date">',
      '<small>' + text(MONTH_NAMES[fromIso(state.selectedDate).getMonth()]) + '</small>',
      '<b>' + text(dayOfMonth(state.selectedDate)) + '</b>',
      '<span>' + text(dayNameLong(state.selectedDate)) + '</span>',
      '</div>',
      '<section>',
      '<h2>Events</h2>',
      selectedEvents.length ? selectedEvents.map(renderInspectorEvent).join("") : '<p class="wt-muted">No visible events.</p>',
      '</section>',
      '<section>',
      '<h2>Deadline Queue</h2>',
      nextDeadlines.map(function (event) {
        return '<div class="wt-deadline-row"><time>' + text(formatDateShort(event.date)) + '</time><b>' + text(event.title) + '</b><small>' + text(event.season || "") + ' ' + text(event.gate || "") + '</small></div>';
      }).join(""),
      '</section>',
      '</aside>'
    ].join("");
  }

  function renderInspectorEvent(event) {
    return [
      '<article class="wt-inspector-event wt-kind-' + text(event.kind) + '">',
      '<small>' + text(event.gate || "WT") + ' · ' + text(event.season || "All") + '</small>',
      '<b>' + text(event.title) + '</b>',
      '<span>' + text(event.time || event.gate || "All day") + ' / ' + text(event.owner || "WT") + '</span>',
      '</article>'
    ].join("");
  }

  function eventTooltip(event) {
    return [
      formatDateShort(event.date),
      event.season || "All",
      event.gate || "WT",
      event.title
    ].filter(Boolean).join(" · ");
  }

  function renderDashboard() {
    var range = currentRange();
    var events = eventsForCurrentRange();
    var selectedEvents = filteredEventsForDate(state.selectedDate);
    return [
      '<section class="wt-dashboard">',
      '<div class="wt-dashboard-hero">',
      '<div><small>24H Projector</small><h2>' + text(formatRange(range)) + '</h2></div>',
      '<div class="wt-now"><span data-clock>--:--</span><small>KST live board</small></div>',
      '</div>',
      '<div class="wt-dashboard-grid">',
      metricCard("Range events", events.length, "Calendar, shipment, report, deadline"),
      metricCard("Sample handoffs", countKind(events, "sample") + countKind(events, "handoff"), "FPT and product gates"),
      metricCard("Report queue", countKind(events, "report"), "AI file analysis"),
      metricCard("Shipping", countKind(events, "shipping"), "Dispatch windows"),
      '</div>',
      '<div class="wt-projector-board">',
      renderCalendarBoard(true),
      '<aside class="wt-today-stack"><h2>' + text(dayNameLong(state.selectedDate)) + '</h2>' + (selectedEvents.length ? selectedEvents.map(renderInspectorEvent).join("") : '<p class="wt-muted">No events selected.</p>') + '</aside>',
      '</div>',
      '</section>'
    ].join("");
  }

  function metricCard(label, value, note) {
    return '<article class="wt-metric"><small>' + text(label) + '</small><b>' + text(value) + '</b><span>' + text(note) + '</span></article>';
  }

  function renderCreationPlan() {
    var events = normalizedEvents().filter(matchesFilters).filter(function (event) {
      return event.season && event.season !== "All";
    });
    var seasons = unique(events.map(function (event) { return event.season; })).slice(0, 8);
    return [
      '<section class="wt-creation">',
      '<div class="wt-plan-map">',
      '<header><small>Season map</small><h2>Creation Plan</h2></header>',
      '<div class="wt-season-lanes">',
      seasons.map(function (season) {
        return renderSeasonLane(season, events.filter(function (event) { return event.season === season; }));
      }).join(""),
      '</div>',
      '</div>',
      '<aside class="wt-plan-side">',
      '<h2>Monthly Load</h2>',
      renderMonthLoad(events),
      '</aside>',
      '</section>'
    ].join("");
  }

  function renderSeasonLane(season, events) {
    var upcoming = events.filter(function (event) { return event.date >= currentRange().start; }).slice(0, 5);
    return [
      '<article class="wt-season-lane">',
      '<div><b>' + text(season) + '</b><span>' + text(events.length) + ' milestones</span></div>',
      '<div class="wt-lane-track">',
      upcoming.map(function (event) {
        return '<button type="button" class="wt-lane-chip wt-kind-' + text(event.kind) + '" data-date="' + text(event.date) + '"><span>' + text(formatDateShort(event.date)) + '</span><b>' + text(event.gate || event.kind) + '</b></button>';
      }).join(""),
      '</div>',
      '</article>'
    ].join("");
  }

  function renderMonthLoad(events) {
    var byMonth = {};
    events.forEach(function (event) {
      var key = event.date.slice(0, 7);
      byMonth[key] = (byMonth[key] || 0) + 1;
    });
    return [
      '<div class="wt-month-load">',
      MONTHS.map(function (month, index) {
        var key = "2026-" + pad(index + 1);
        var count = byMonth[key] || 0;
        return '<article><b>' + text(month) + '</b><span style="--load:' + text(Math.min(100, count * 12)) + '%"></span><small>' + text(count) + '</small></article>';
      }).join(""),
      '</div>'
    ].join("");
  }

  function renderLibraries() {
    var rows = [
      ["Schedule PDF extraction", "153 milestones", "Active"],
      ["WT report analysis", "AI review queue", "Ready"],
      ["Shipping calendar", "Manual entry", "Draft"],
      ["SharePoint list sync", "WT_Submissions", "Active"]
    ];
    return [
      '<section class="wt-libraries">',
      '<div class="wt-library-main">',
      '<header><small>Libraries</small><h2>Source Control</h2></header>',
      rows.map(function (row) {
        return '<article class="wt-library-row"><div><b>' + text(row[0]) + '</b><span>' + text(row[1]) + '</span></div><small>' + text(row[2]) + '</small></article>';
      }).join(""),
      '</div>',
      '<aside class="wt-report-panel">',
      '<h2>Report Queue</h2>',
      renderReportItem("Wear-test comments", "24 files", "Review"),
      renderReportItem("Sample defect notes", "8 files", "Extract"),
      renderReportItem("Shipment evidence", "13 files", "Match"),
      '</aside>',
      '</section>'
    ].join("");
  }

  function renderReportItem(title, count, status) {
    return '<article class="wt-report-item"><b>' + text(title) + '</b><span>' + text(count) + '</span><small>' + text(status) + '</small></article>';
  }

  function renderEditor(root) {
    return [
      '<main class="wt-main wt-editor" aria-label="Schedule editor">',
      '<header class="wt-toolbar">',
      '<div class="wt-title-block"><small>WT Operations</small><h1>Create Deadline</h1></div>',
      '<button class="wt-toolbar-create" type="button" data-view="display">Projector</button>',
      '</header>',
      '<div class="wt-editor-layout">',
      '<section class="wt-editor-calendar">',
      renderCalendarControls(),
      renderCalendarBoard(false),
      '</section>',
      renderEditForm(root),
      '</div>',
      '</main>'
    ].join("");
  }

  function renderEditForm(root) {
    var listTitle = root.getAttribute("data-wt-sharepoint-list-title") || "WT_Submissions";
    return [
      '<aside class="wt-edit-card">',
      '<h2>Schedule Input</h2>',
      '<form class="wt-edit-form">',
      field("Title", "HO27 sample dispatch"),
      '<label>Date<input name="targetDate" type="date" value="' + text(state.selectedDate) + '"></label>',
      select("Type", ["deadline", "sample", "shipping", "report", "review"]),
      select("Season", ["HO27", "SP28", "SU27", "FA27", "SP27"]),
      field("Owner", "WT Ops"),
      '<label>Memo<textarea name="notes" rows="5" placeholder="Model, sample size, report file, shipment note"></textarea></label>',
      '<p class="wt-form-message" aria-live="polite">Target list: ' + text(listTitle) + '</p>',
      '<button class="primary" type="submit">Save Schedule</button>',
      '</form>',
      '</aside>'
    ].join("");
  }

  function field(label, placeholder) {
    var name = label.toLowerCase().replace(/[^a-z0-9]+/g, "-");
    return '<label>' + text(label) + '<input name="' + text(name) + '" type="text" placeholder="' + text(placeholder) + '"></label>';
  }

  function select(label, options) {
    var name = label.toLowerCase().replace(/[^a-z0-9]+/g, "-");
    return '<label>' + text(label) + '<select name="' + text(name) + '">' + options.map(function (option) {
      return '<option value="' + text(option) + '">' + text(option) + '</option>';
    }).join("") + '</select></label>';
  }

  function renderMiniMonth(isoMonth) {
    var days = buildMonth(isoMonth);
    return [
      '<div class="wt-mini-month">',
      '<header><span>2026</span><b>JUN</b></header>',
      '<div class="wt-mini-week">' + WEEKDAYS.map(function (day) { return '<span>' + text(day.charAt(0)) + '</span>'; }).join("") + '</div>',
      '<div class="wt-mini-days">',
      days.map(function (day) {
        if (!day) return '<span></span>';
        var date = isoMonth + "-" + pad(day);
        var hasEvent = normalizedEvents().some(function (event) { return event.date === date; });
        return '<button type="button" class="' + (date === state.selectedDate ? "active " : "") + (hasEvent ? "has-event" : "") + '" data-date="' + text(date) + '">' + text(day) + '</button>';
      }).join(""),
      '</div>',
      '</div>'
    ].join("");
  }

  function submitSchedule(root, form) {
    var message = root.querySelector(".wt-form-message");
    var mode = root.getAttribute("data-wt-backend-mode") || "local";
    var payload = {
      rowKey: "WT-" + Date.now(),
      submittedAt: new Date().toISOString(),
      projectName: form.elements.title ? form.elements.title.value : "",
      targetDate: form.elements.targetDate ? form.elements.targetDate.value : "",
      milestoneType: form.elements.type ? form.elements.type.value : "",
      season: form.elements.season ? form.elements.season.value : "",
      source: "wt-system-ui",
      owner: form.elements.owner ? form.elements.owner.value : "",
      notes: form.elements.notes ? form.elements.notes.value : ""
    };

    if (mode === "sharepoint-list") {
      submitToSharePointList(root, payload).then(function () {
        saveLocalSubmission(payload);
        if (message) message.textContent = "Saved to WT_Submissions.";
      }).catch(function (error) {
        if (message) message.textContent = "SharePoint save failed: " + error.message;
      });
      return;
    }

    try {
      saveLocalSubmission(payload);
      if (message) message.textContent = "Saved locally for preview.";
      state.selectedDate = payload.targetDate || state.selectedDate;
      render(root);
    } catch (error) {
      if (message) message.textContent = "Local save failed: " + error.message;
    }
  }

  function exportCurrentRange(root) {
    var range = currentRange();
    var rows = eventsForCurrentRange().map(function (event) {
      return [
        event.date,
        event.endDate || event.date,
        event.title,
        event.kind,
        event.season || "",
        event.gate || "",
        event.owner || "",
        event.source || ""
      ];
    });
    var csv = [
      ["startDate", "endDate", "title", "type", "season", "gate", "owner", "source"],
    ].concat(rows).map(function (row) {
      return row.map(csvCell).join(",");
    }).join("\n");
    var blob = new window.Blob([csv], { type: "text/csv;charset=utf-8" });
    var link = document.createElement("a");
    link.href = window.URL.createObjectURL(blob);
    link.download = "wt-calendar-" + range.start + "-" + range.end + ".csv";
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
    window.URL.revokeObjectURL(link.href);
    state.actionMessage = "Exported " + rows.length + " events for " + formatRange(range) + ".";
    render(root);
  }

  function csvCell(value) {
    var stringValue = String(value == null ? "" : value);
    return '"' + stringValue.replace(/"/g, '""') + '"';
  }

  function saveLocalSubmission(payload) {
    var existing = JSON.parse(window.localStorage.getItem("wt-system-submissions") || "[]");
    existing.push(payload);
    window.localStorage.setItem("wt-system-submissions", JSON.stringify(existing));
  }

  function submitToSharePointList(root, payload) {
    var listTitle = root.getAttribute("data-wt-sharepoint-list-title") || "WT_Submissions";
    var sitePath = getSitePath();
    return getDigest(sitePath).then(function (digest) {
      return window.fetch(sitePath + "/_api/web/lists/getbytitle('" + encodeODataString(listTitle) + "')/items", {
        method: "POST",
        credentials: "same-origin",
        headers: {
          "Accept": "application/json;odata=nometadata",
          "Content-Type": "application/json;odata=nometadata",
          "X-RequestDigest": digest
        },
        body: JSON.stringify({
          Title: payload.projectName || "WT schedule",
          RowKey: payload.rowKey,
          PayloadJson: JSON.stringify(payload),
          SubmittedAt: payload.submittedAt,
          IsActive: true
        })
      }).then(function (response) {
        if (!response.ok) throw new Error("HTTP " + response.status);
        return response.json();
      });
    });
  }

  function getDigest(sitePath) {
    return window.fetch(sitePath + "/_api/contextinfo", {
      method: "POST",
      credentials: "same-origin",
      headers: { "Accept": "application/json;odata=nometadata" }
    }).then(function (response) {
      if (!response.ok) throw new Error("Digest HTTP " + response.status);
      return response.json();
    }).then(function (data) {
      return data.FormDigestValue;
    });
  }

  function getSitePath() {
    var match = window.location.pathname.match(/^(\/sites\/[^/]+)/);
    return match ? match[1] : "";
  }

  function encodeODataString(value) {
    return String(value).replace(/'/g, "''");
  }

  function normalizedEvents() {
    var events = [];
    (EMBEDDED.milestones || []).forEach(function (item) {
      if (!item.date || item.source !== "schedule.pdf") return;
      events.push({
        id: item.id,
        date: item.date,
        endDate: item.endDate || item.date,
        title: item.task || item.gate || "Milestone",
        kind: mapMilestoneKind(item.kind),
        season: item.season || "All",
        gate: item.gate || "",
        owner: item.gate || "WT",
        time: "",
        source: "schedule.pdf"
      });
    });

    return events.filter(function (event) {
      return !!event.date;
    }).sort(function (a, b) {
      return (a.date + a.title).localeCompare(b.date + b.title);
    });
  }

  function loadLocalSubmissions() {
    try {
      return JSON.parse(window.localStorage.getItem("wt-system-submissions") || "[]");
    } catch (error) {
      return [];
    }
  }

  function mapMilestoneKind(kind) {
    if (kind === "sample_to_fpt" || kind === "sample_ddd") return "sample";
    if (kind === "handoff") return "handoff";
    if (kind === "results_ready") return "report";
    if (kind === "design_revisions_due" || kind === "revisions_ddd") return "deadline";
    if (kind === "scrutiny" || kind === "x_fty") return "review";
    if (kind === "bom_ddd" || kind === "product_freeze") return "creation";
    return "deadline";
  }

  function matchesFilters(event) {
    var seasonMatch = state.season === "All" || event.season === state.season || event.season === "All";
    var deadlineMatch = !state.deadlineOnly || event.kind === "deadline" || event.kind === "handoff";
    var searchMatch = matchesSearch(event);
    return seasonMatch && deadlineMatch && searchMatch;
  }

  function matchesSearch(event) {
    var query = state.search.trim().toLowerCase();
    if (!query) return true;
    return [
      event.title,
      event.season,
      event.gate,
      event.owner,
      event.kind
    ].join(" ").toLowerCase().indexOf(query) >= 0;
  }

  function filteredEventsForDate(date) {
    return normalizedEvents().filter(matchesFilters).filter(function (event) {
      return event.date === date;
    });
  }

  function filteredEventsForRange(startIso, endIso) {
    return normalizedEvents().filter(matchesFilters).filter(function (event) {
      return eventOverlapsRange(event, startIso, endIso);
    });
  }

  function eventsForCurrentRange() {
    var range = currentRange();
    return filteredEventsForRange(range.start, range.end);
  }

  function eventOverlapsRange(event, startIso, endIso) {
    var start = event.date;
    var end = event.endDate || event.date;
    return start <= endIso && end >= startIso;
  }

  function countKind(events, kind) {
    return events.filter(function (event) { return event.kind === kind; }).length;
  }

  function unique(items) {
    var seen = {};
    return items.filter(function (item) {
      if (!item || seen[item]) return false;
      seen[item] = true;
      return true;
    });
  }

  function currentRange() {
    return periodRange(state.weekStart, state.period);
  }

  function periodRange(anchorIso, period) {
    var anchor = fromIso(anchorIso);
    if (period === "multi-week") {
      var multiWeekStart = startOfWeek(anchor);
      return { start: toIso(multiWeekStart), end: toIso(addDays(multiWeekStart, 27)) };
    }
    if (period === "month") {
      return monthRange(anchor);
    }
    if (period === "multi-month") {
      var multiMonthStart = new Date(anchor.getFullYear(), anchor.getMonth(), 1);
      var multiMonthEnd = addDays(addMonths(multiMonthStart, 3), -1);
      return { start: toIso(multiMonthStart), end: toIso(multiMonthEnd) };
    }
    if (period === "quarter") {
      var quarterStartMonth = Math.floor(anchor.getMonth() / 3) * 3;
      var quarterStart = new Date(anchor.getFullYear(), quarterStartMonth, 1);
      var quarterEnd = addDays(addMonths(quarterStart, 3), -1);
      return { start: toIso(quarterStart), end: toIso(quarterEnd) };
    }
    if (period === "season") {
      return seasonRange(anchorIso);
    }
    var weekStart = startOfWeek(anchor);
    return { start: toIso(weekStart), end: toIso(addDays(weekStart, 6)) };
  }

  function seasonRange(anchorIso) {
    var seasonEvents = normalizedEvents().filter(function (event) {
      return state.season !== "All" && event.season === state.season;
    });
    if (seasonEvents.length) {
      return {
        start: seasonEvents[0].date,
        end: seasonEvents[seasonEvents.length - 1].endDate || seasonEvents[seasonEvents.length - 1].date
      };
    }
    var year = fromIso(anchorIso).getFullYear();
    return { start: year + "-01-01", end: year + "-12-31" };
  }

  function periodAnchor(iso, period) {
    return periodRange(iso, period).start;
  }

  function moveRange(direction) {
    var current = currentRange();
    var start = fromIso(current.start);
    if (state.period === "month") {
      state.weekStart = periodAnchor(toIso(addMonths(start, direction)), state.period);
      return;
    }
    if (state.period === "multi-month" || state.period === "quarter") {
      state.weekStart = periodAnchor(toIso(addMonths(start, direction * 3)), state.period);
      return;
    }
    if (state.period === "season") {
      state.weekStart = periodAnchor(toIso(addMonths(start, direction * 6)), state.period);
      return;
    }
    var amount = state.period === "multi-week" ? direction * 28 : direction * 7;
    state.weekStart = periodAnchor(toIso(addDays(start, amount)), state.period);
  }

  function monthRange(date) {
    var start = new Date(date.getFullYear(), date.getMonth(), 1);
    var end = new Date(date.getFullYear(), date.getMonth() + 1, 0);
    return { start: toIso(start), end: toIso(end) };
  }

  function addMonths(date, amount) {
    var copy = new Date(date.getFullYear(), date.getMonth(), 1);
    copy.setMonth(copy.getMonth() + amount);
    return copy;
  }

  function buildMonth(isoMonth) {
    var parts = isoMonth.split("-");
    var year = Number(parts[0]);
    var monthIndex = Number(parts[1]) - 1;
    var first = new Date(year, monthIndex, 1);
    var total = new Date(year, monthIndex + 1, 0).getDate();
    var days = [];
    var mondayOffset = (first.getDay() + 6) % 7;
    for (var i = 0; i < mondayOffset; i += 1) days.push(null);
    for (var day = 1; day <= total; day += 1) days.push(day);
    while (days.length % 7) days.push(null);
    return days;
  }

  function weekDays(startIso) {
    var start = fromIso(startIso);
    var days = [];
    for (var i = 0; i < 7; i += 1) {
      days.push(toIso(addDays(start, i)));
    }
    return days;
  }

  function startOfWeek(date) {
    var copy = new Date(date.getFullYear(), date.getMonth(), date.getDate());
    var offset = (copy.getDay() + 6) % 7;
    return addDays(copy, -offset);
  }

  function addDaysIso(date, amount) {
    return toIso(addDays(fromIso(date), amount));
  }

  function addDays(date, amount) {
    var copy = new Date(date.getFullYear(), date.getMonth(), date.getDate());
    copy.setDate(copy.getDate() + amount);
    return copy;
  }

  function fromIso(iso) {
    var parts = iso.split("-").map(Number);
    return new Date(parts[0], parts[1] - 1, parts[2]);
  }

  function toIso(date) {
    return [date.getFullYear(), pad(date.getMonth() + 1), pad(date.getDate())].join("-");
  }

  function dayOfMonth(date) {
    return fromIso(date).getDate();
  }

  function dayNameShort(date) {
    return WEEKDAYS[(fromIso(date).getDay() + 6) % 7];
  }

  function dayNameLong(date) {
    return ["Sunday", "Monday", "Tuesday", "Wednesday", "Thursday", "Friday", "Saturday"][fromIso(date).getDay()];
  }

  function formatWeekRange(startIso) {
    var start = fromIso(startIso);
    var end = addDays(start, 6);
    return MONTHS[start.getMonth()] + " " + start.getDate() + " - " + MONTHS[end.getMonth()] + " " + end.getDate();
  }

  function formatRange(range) {
    var start = fromIso(range.start);
    var end = fromIso(range.end);
    var startText = titleCaseMonth(start) + " " + start.getDate();
    var endText = titleCaseMonth(end) + " " + end.getDate();
    if (start.getFullYear() !== end.getFullYear()) {
      return startText + ", " + start.getFullYear() + " - " + endText + ", " + end.getFullYear();
    }
    return startText + " - " + endText;
  }

  function formatDateShort(date) {
    var d = fromIso(date);
    return titleCaseMonth(d) + " " + d.getDate();
  }

  function titleCaseMonth(date) {
    var month = MONTHS[date.getMonth()].toLowerCase();
    return month.charAt(0).toUpperCase() + month.slice(1);
  }

  function calendarViewLabel(id) {
    var option = CALENDAR_VIEWS.filter(function (view) { return view.id === id; })[0];
    return option ? option.label : "Timeline View";
  }

  function periodLabel(id) {
    var option = PERIODS.filter(function (period) { return period.id === id; })[0];
    return option ? option.label : "1 week";
  }

  function timelineUnits(range) {
    var days = daysBetween(range.start, range.end) + 1;
    if (days <= 14) return dayUnits(range);
    if (days <= 120) return weekUnits(range);
    return monthUnits(range);
  }

  function dayUnits(range) {
    var units = [];
    var count = daysBetween(range.start, range.end);
    for (var i = 0; i <= count; i += 1) {
      var date = addDaysIso(range.start, i);
      units.push({
        start: date,
        end: date,
        label: dayNameShort(date),
        caption: String(dayOfMonth(date))
      });
    }
    return units;
  }

  function weekUnits(range) {
    var units = [];
    var cursor = startOfWeek(fromIso(range.start));
    while (toIso(cursor) <= range.end) {
      var start = toIso(cursor);
      var end = toIso(addDays(cursor, 6));
      units.push({
        start: start < range.start ? range.start : start,
        end: end > range.end ? range.end : end,
        label: formatDateShort(start),
        caption: "Week"
      });
      cursor = addDays(cursor, 7);
    }
    return units;
  }

  function monthUnits(range) {
    var units = [];
    var cursor = new Date(fromIso(range.start).getFullYear(), fromIso(range.start).getMonth(), 1);
    while (toIso(cursor) <= range.end) {
      var month = monthRange(cursor);
      units.push({
        start: month.start < range.start ? range.start : month.start,
        end: month.end > range.end ? range.end : month.end,
        label: MONTHS[cursor.getMonth()],
        caption: String(cursor.getFullYear())
      });
      cursor = addMonths(cursor, 1);
    }
    return units;
  }

  function eventUnitPosition(event, units) {
    var start = event.date;
    var end = event.endDate || event.date;
    var startIndex = 0;
    var endIndex = units.length - 1;
    for (var i = 0; i < units.length; i += 1) {
      if (units[i].end >= start) {
        startIndex = i;
        break;
      }
    }
    for (var j = startIndex; j < units.length; j += 1) {
      if (units[j].start <= end && units[j].end >= end) {
        endIndex = j;
        break;
      }
    }
    return { start: startIndex + 1, span: Math.max(1, endIndex - startIndex + 1) };
  }

  function unitHasToday(unit) {
    var todayIso = toIso(new Date());
    return unit.start <= todayIso && unit.end >= todayIso;
  }

  function daysBetween(startIso, endIso) {
    return Math.round((fromIso(endIso).getTime() - fromIso(startIso).getTime()) / 86400000);
  }

  function pad(value) {
    return String(value).padStart(2, "0");
  }

  function updateClock(root) {
    var targets = root.querySelectorAll("[data-clock]");
    if (!targets.length) return;
    var now = new Date();
    var value = pad(now.getHours()) + ":" + pad(now.getMinutes());
    for (var i = 0; i < targets.length; i += 1) targets[i].textContent = value;
  }

  function text(value) {
    return String(value)
      .replace(/&/g, "&amp;")
      .replace(/</g, "&lt;")
      .replace(/>/g, "&gt;")
      .replace(/"/g, "&quot;")
      .replace(/'/g, "&#39;");
  }

  if (document.readyState === "loading") {
    document.addEventListener("DOMContentLoaded", boot);
  } else {
    boot();
  }
})();
